```

And add the helper function `normalizePartialDate` somewhere before `buildPayload` in `NumuneFormClient.tsx`:
```typescript
function normalizePartialDate(v: string): string | null {
  if (!v) return null;
  const parts = v.split("-");
  if (parts.length === 1) return `${parts[0]}-01-01`;     // year only
  if (parts.length === 2) return `${parts[0]}-${parts[1]}-01`; // year+month
  return v; // full date
}
```

