36	function FirmaSearch({
37	  label, value, displayValue, onChange, placeholder,
38	}: {
39	  label: string;
40	  value: number | null;
41	  displayValue: string;
42	  onChange: (id: number | null, ad: string) => void;
43	  placeholder?: string;
44	}) {
45	  const [q, setQ]           = useState(displayValue);
46	  const [results, setRes]   = useState<{ ID: number; Ad: string }[]>([]);
47	  const [open, setOpen]     = useState(false);
48	  const timer               = useRef<ReturnType<typeof setTimeout> | null>(null);
49	  const wrapRef             = useRef<HTMLDivElement>(null);
50	
51	  useEffect(() => { setQ(displayValue); }, [displayValue]);
52	
53	  useEffect(() => {
54	    const handler = (e: MouseEvent) => {
55	      if (wrapRef.current && !wrapRef.current.contains(e.target as Node)) {
56	        setOpen(false);
57	      }
58	    };
59	    document.addEventListener("mousedown", handler);
60	    return () => document.removeEventListener("mousedown", handler);
61	  }, []);
62	
63	  const search = useCallback((val: string) => {
64	    if (timer.current) clearTimeout(timer.current);
65	    timer.current = setTimeout(async () => {
66	      if (val.trim().length < 1) { setRes([]); setOpen(false); return; }
67	      try {
68	        const r = await fetch(`/api/numune-form/firmalar?q=${encodeURIComponent(val)}`);
69	        const data = await r.json();
70	        setRes(data);
71	        setOpen(data.length > 0);
72	      } catch { setRes([]); }
73	    }, 200);
74	  }, []);
75	
76	  return (
77	    <div className={styles.formGroup} ref={wrapRef} style={{ position: "relative" }}>
78	      <label>{label}</label>
79	      <input
80	        value={q}
81	        placeholder={placeholder || "Yazmaya başlayın…"}
82	        onChange={e => { setQ(e.target.value); search(e.target.value); if (!e.target.value) onChange(null, ""); }}
83	        onFocus={() => { if (results.length) setOpen(true); }}
84	        autoComplete="off"
85	      />
86	      {value ? (
87	        <button
88	          type="button"
89	          onClick={() => { onChange(null, ""); setQ(""); setRes([]); }}
90	          style={{ position: "absolute", right: 8, top: 28, background: "none", border: "none", cursor: "pointer", color: "var(--color-text-tertiary)", fontSize: "0.8rem" }}
91	          aria-label="Temizle"
92	        >✕</button>
93	      ) : null}
94	      {open && results.length > 0 ? (
95	        <div style={{
96	          position: "absolute", zIndex: 300, top: "100%", left: 0, right: 0,
97	          background: "var(--color-surface)", border: "1px solid var(--color-border)",
98	          borderRadius: "var(--radius-sm)", boxShadow: "0 4px 16px rgba(0,0,0,0.12)",
99	          maxHeight: 200, overflowY: "auto",
100	        }}>
101	          {results.map(r => (
102	            <div
103	              key={r.ID}
104	              style={{
105	                padding: "8px 12px", cursor: "pointer", fontSize: "0.845rem",
106	                borderBottom: "1px solid var(--color-border-light)",
107	                background: r.ID === value ? "var(--color-accent-light)" : "transparent",
108	              }}
109	              onMouseDown={() => { onChange(r.ID, r.Ad); setQ(r.Ad); setOpen(false); }}
110	            >
111	              {r.Ad}
112	            </div>
113	          ))}
114	        </div>
115	      ) : null}
116	    </div>
117	  );
118	}
