120	function WebcamModal({ onCapture, onClose }: { onCapture: (dataUrl: string) => void; onClose: () => void }) {
121	  const videoRef  = useRef<HTMLVideoElement>(null);
122	  const canvasRef = useRef<HTMLCanvasElement>(null);
123	  const [stream, setStream] = useState<MediaStream | null>(null);
124	  const [error, setError]   = useState("");
125	
126	  useEffect(() => {
127	    navigator.mediaDevices.getUserMedia({ video: true })
128	      .then(s => { setStream(s); if (videoRef.current) videoRef.current.srcObject = s; })
129	      .catch(() => setError("Kamera erişimi reddedildi."));
130	    return () => stream?.getTracks().forEach(tr => tr.stop());
131	  }, []);
132	
133	  const capture = () => {
134	    if (!videoRef.current || !canvasRef.current) return;
135	    const v = videoRef.current;
136	    const c = canvasRef.current;
137	    c.width  = v.videoWidth;
138	    c.height = v.videoHeight;
139	    c.getContext("2d")!.drawImage(v, 0, 0);
140	    onCapture(c.toDataURL("image/jpeg", 0.85));
141	    stream?.getTracks().forEach(tr => tr.stop());
142	  };
143	
144	  return (
145	    <div className={styles.modalOverlay} onClick={onClose}>
146	      <div className={styles.modal} style={{ maxWidth: 500 }} onClick={e => e.stopPropagation()}>
147	        <div className={styles.modalHeader}>
148	          <h2>Kameradan Çek</h2>
149	          <button type="button" className={styles.modalClose} onClick={() => { stream?.getTracks().forEach(tr => tr.stop()); onClose(); }}>✕</button>
150	        </div>
151	        <div className={styles.modalBody} style={{ textAlign: "center" }}>
152	          {error
153	            ? <p style={{ color: "var(--color-danger)" }}>{error}</p>
154	            : <video ref={videoRef} autoPlay playsInline style={{ width: "100%", borderRadius: 8 }} />
155	          }
156	          <canvas ref={canvasRef} style={{ display: "none" }} />
157	        </div>
158	        <div className={styles.modalFooter}>
159	          <button type="button" className={styles.cancelBtn} onClick={() => { stream?.getTracks().forEach(tr => tr.stop()); onClose(); }}>İptal</button>
160	          <button type="button" className={styles.saveBtn} onClick={capture} disabled={!!error}>Çek</button>
161	        </div>
162	      </div>
163	    </div>
164	  );
165	}
