const AYLAR = ["Oca","Şub","Mar","Nis","May","Haz","Tem","Ağu","Eyl","Eki","Kas","Ara"];

// Accepts: "" | "YYYY" | "YYYY-MM" | "YYYY-MM-DD"
// Stores partial dates as-is; API will pad with -01 when saving to DB.
function PartialDateInput({ value, onChange }: { value: string; onChange: (v: string) => void }) {
  const parts = value ? value.split("-") : [];
  const yil = parts[0] ?? "";
  const ay  = parts[1] ?? "";
  const gun = parts[2] ?? "";

  const update = (newY: string, newM: string, newD: string) => {
    if (!newY) { onChange(""); return; }
    if (!newM)  { onChange(newY); return; }
    if (!newD)  { onChange(`${newY}-${newM.padStart(2, "0")}`); return; }
    onChange(`${newY}-${newM.padStart(2, "0")}-${newD.padStart(2, "0")}`);
  };

  const selectStyle: React.CSSProperties = {
    flex: "0 0 auto",
    padding: "6px 4px",
    border: "1px solid var(--color-border)",
    borderRadius: "var(--radius-sm)",
    background: "var(--color-surface)",
    color: "var(--color-text-primary)",
    fontSize: "0.8125rem",
    cursor: "pointer",
  };

  return (
    <div style={{ display: "flex", gap: 4, alignItems: "center" }}>
      <input
        type="number"
        min={1990}
        max={2100}
        placeholder="Yıl"
        value={yil}
        onChange={e => update(e.target.value, ay, gun)}
        style={{ ...selectStyle, width: 68, textAlign: "center" }}
      />
      <select value={ay} onChange={e => update(yil, e.target.value, gun)} style={{ ...selectStyle, width: 68 }}>
        <option value="">Ay</option>
        {AYLAR.map((a, i) => (
          <option key={i} value={String(i + 1).padStart(2, "0")}>{a}</option>
        ))}
      </select>
      <select value={gun} onChange={e => update(yil, ay, e.target.value)} disabled={!ay} style={{ ...selectStyle, width: 56 }}>
        <option value="">Gün</option>
        {Array.from({ length: 31 }, (_, i) => (
          <option key={i + 1} value={String(i + 1).padStart(2, "0")}>{i + 1}</option>
        ))}
      </select>
    </div>
  );
}

