  align-items: center;
  gap: 6px;
  padding: 7px 18px;
  background: var(--color-accent);
  color: #fff;
  border: none;
  border-radius: var(--radius-sm);
  font-size: 0.8125rem;
  font-weight: 600;
  cursor: pointer;
  transition: opacity 0.15s;
}
.saveCardBtn:hover { opacity: 0.88; }
.saveCardBtn:disabled { opacity: 0.5; cursor: not-allowed; }

.cardErr {
  padding: 8px 12px;
  background: var(--color-danger-light);
  color: var(--color-danger);
  font-size: 0.8rem;
  border-radius: var(--radius-sm);
}

/* Hizmetler mini bölümü */
.hizmetSection {
  border-top: 1px solid var(--color-border-light);
  padding-top: 12px;
}

.hizmetSectionTitle {
  font-size: 0.75rem;
  font-weight: 650;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--color-text-secondary);
  margin-bottom: 8px;
}

/* formGroup (lokal — yansıtmak için import yerine inline) */
.fg {
  display: flex;
  flex-direction: column;
  gap: 4px;
}
.fg label {
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--color-text-secondary);
}
