}

interface NumuneCard {
  cardId: string;
  savedId: number | null;
  RaporNo: string;
  Numune_Adi: string;
  Numune_Adi_En: string;
  Tur: string;
  Barkod: string;
  Miktar: string;
  Birim: string;
  TesteMiktar: string;
  TesteMiktarBirim: string;
  SeriNo: string;
  UretimTarihi: string;
  SKT: string;
  Aciklama: string;
  Urun_Tipi: string;
  UGDTip_ID: number | null;
  Hedef_Grup: string;
  hizmetler: HizmetRow[];
